function toHeaderSafeFilename(str) {
  const s = String(str || "")
    .trim()
    .replace(/\.(png|jpg|jpeg|webp|gif)$/i, "") // strip extension if present
    .normalize("NFKD")
    .replace(/[\u00A0\u2000-\u200B\u202F\u205F\u3000]/g, "") // remove weird spaces
    .replace(/[\u0300-\u036f]/g, "") // accents
    .replace(/[—–]/g, "")           // long dashes
    .replace(/&/g, "and")
    .replace(/['"`]/g, "")
    .replace(/[:;,.!?(){}\[\]|<>]/g, "")
    .replace(/[^a-zA-Z0-9]/g, "")   // ❗ remove EVERYTHING except letters+numbers
    .slice(0, 80);

  return s || "image";
}

